window.onclick = function (event) {
  if (
    !$(event.target).closest(".modal-content").length &&
    !$(event.target).closest("[data-modal]").length &&
    !$(event.target).closest("[onclick]").length
  ) {
    md.close();
  }
  //dropdown
  if (
    !$(event.target).closest("[data-dropdown]").length &&
    !$(event.target).closest(".dropdown").length
  ) {
    $(".dropdown").removeClass("open");
  } else if ($(event.target).closest("[data-dropdown]").length) {
    var evt = $(event.target).closest("[data-dropdown]");
    $(".dropdown").removeClass("open");
    evt.closest(".dropdown").addClass("open");
  }
};
var Login = 0,
  md = {
    int: function () {
      $("[data-modal]").click(function (event) {
        event.preventDefault();
        md.close();
        $($(this).data("modal")).show();
      });
      $(".modal .close").click(function (event) {
        event.preventDefault();
        md.close();
      });
      if ($("#pwd_change").length) {
        $('input[name="pwd_change"]').change(function () {
          if ($(this).is(":checked") == true) {
            $("#pwd_change").show().find("input").attr("required", true);
          } else {
            $("#pwd_change").hide().find("input").removeAttr("required");
          }
        });
      }
    },
    close: function () {
      $(".modal").hide();
    },
    Form: function () {
      $("[data-action]").unbind("submit");
      $("[data-action]").submit(function (event) {
        let $evt = $(this);
        let Action = $evt.data("action");
        $evt
          .find("[type='submit']")
          .prop("disabled", !0)
          .html('<i class="fa fa-circle-o-notch fa-spin"></i> Waiting...');
        $evt.find(".help-block").remove();
        $evt.find(".has-error").removeClass("has-error");

        const Data = new FormData(this);
        if ($evt.find('input[type="file"]').length > 0) {
          $.each($evt.find('input[type="file"]'), function (i, tag) {
            $.each($(tag)[0].files, function (i, file) {
              Data.append(tag.name, file);
            });
          });
        }
        var error = [];
        let mLoad = $("#main-loading").length ? 1 : 0;
        if (mLoad) $("#main-loading").show();
        $.ajax({
          url: Action + "?__=" + Math.floor(Date.now() / 1000),
          type: "POST",
          data: Data,
          cache: false,
          processData: false,
          contentType: false,
          dataType: "JSON",
          success: function (t) {
            if (t.status == 1) {
              if (t.ajax == "addCart") {
                $("#order-modal").modal("hide");
                $.toast({
                  heading: "Awesome!",
                  text: "Item has been added to your Cart!",
                  icon: "success",
                  position: "top-right",
                });
                $(".cart-count").text(t.count);
                return false;
              }
              if (t.alert == 1) {
                alert(t.message);
              }
              if (t.url) location.href = t.url;
              else location.reload();
            } else {
              $.each(t.message, function (k, message) {
                var block = $evt.find("[name='" + k + "']").parent();
                var label =
                  message == 1
                    ? block.find("label").text() + " is required"
                    : message;
                $evt.find("[name='" + k + "']").addClass("is-invalid");
                block.addClass("has-error");
                if (block.hasClass("material-field")) block = block.parent();
                block.append('<span class="help-block">' + label + "</span>");
                $evt.find("[type='submit']").removeAttr("disabled"),
                  $evt.find("[type='submit']").html("Resend");
                error.push(label);
              });
              if (mLoad) $("#main-loading").hide();
            }
          },
        }),
          event.preventDefault();
      });
    },
    auth: function () {
      $.get(
        "/ajax/session?__=" + Math.floor(Date.now() / 1000),
        function (j) {
          if (j.status) {
            $(".member").addClass("isLogin").html(`
          <ul>
            <li class="dropdown">
              <a href="#" data-dropdown="true"><i class="fa fa-user-circle"></i><span class="text"> ${j.profile}</span></a>
              <ul class="menu">
                <li><a href="/profile/">${j.profile}</a></li>
                <li><a href="/following/">${j.following}</a></li>
                <li><a href="/logout/">${j.logout}</a></li>
              </ul>
            </li>
            <li class="dropdown notify-ui">
              <a href="#" onclick="md.notify(1)" data-dropdown="true"><i class="fa fa-bell-o"></i><span data-count="0" class="tbcount">0</span></a>
              <ul class="w300">
                <li class="nodata">${j.nodata}</li>
              </ul>
            </li>
          </ul>
          `);
            Login = 1;
            md.notify();
            setInterval(function () {
              md.notify();
            }, 10 * 1000);
          }
        },
        "json"
      );
    },
    notify: function (read) {
      $.get(
        "/ajax/notify" +
          (read == 1 ? ".read" : "") +
          "?__=" +
          Math.floor(Date.now() / 1000),
        function (j) {
          if (read == 1) {
            $(".notify-ui")
              .find(".tbcount")
              .data("count", 0)
              .attr("data-count", 0);
          } else {
            if (j.status) {
              $(".notify-ui")
                .find(".tbcount")
                .data("count", j.total)
                .attr("data-count", j.total)
                .text(j.total > 99 ? "99+" : j.total);
              $(".notify-ui>ul").html(j.notify);
            }
          }
        },
        "json"
      );
    },
    follow: function (evt, id) {
      if (Login == 1) {
        let rm = Number($(evt).data("remove"));
        $.post(
          "/ajax/follow?__=" + Math.floor(Date.now() / 1000),
          { id, rm },
          function (j) {
            if (j.status) {
              if (rm == 1) {
                if ($(evt).data("rm") == 1) {
                  $(evt).closest(".manga").remove();
                } else {
                  $(evt)
                    .data("remove", 0)
                    .removeClass("selected")
                    .html('<i class="fa fa-heart-o"></i><span> '+lang[1]+'</span>');
                }
              } else {
                $(evt)
                  .data("remove", 1)
                  .addClass("selected")
                  .html('<i class="fa fa-heart"></i> <span> '+lang[2]+'</span>');
              }
            }
          },
          "json"
        );
      } else {
        $("#MLogin").show();
      }
    },
  };
md.int();
md.Form();
md.auth();
